+    #[cfg(test)]
+    #[test]
+    fn test_statement_reuse_trace_records_prepared_cache_reuse_distance() {
+        let _profile_guard = StatementReuseHotPathProfileGuard::new();
+        let conn = Connection::open(":memory:").unwrap();
+        let hot_sql = "SELECT 1";
+        let cold_sql = "SELECT 2";
+        let hot_fingerprint = format!("{:016x}", Connection::sql_hash(hot_sql));
+
+        reset_statement_reuse_measurement(&conn);
+        let _lane = StatementReuseLaneOverrideGuard::new("worker-01", "node-a");
+        drop(conn.prepare(hot_sql).unwrap());
+        drop(conn.prepare(cold_sql).unwrap());
+        drop(conn.prepare(hot_sql).unwrap());
+
+        let prepared_events = conn
+            .statement_reuse_trace_snapshot()
+            .into_iter()
+            .filter(|entry| {
+                entry.cache_kind == "prepared" && entry.statement_fingerprint == hot_fingerprint
+            })
+            .collect::<Vec<_>>();
+
+        assert_eq!(
+            prepared_events.len(),
+            2,
+            "hot SQL should produce one miss and one hit trace entry"
+        );
+        assert_eq!(prepared_events[0].reuse_distance, None);
+        assert_eq!(prepared_events[0].lane_locality, StatementReuseLaneLocality::FirstObservation);
+        assert_eq!(prepared_events[1].reuse_distance, Some(1));
+        assert_eq!(prepared_events[1].lane_locality, StatementReuseLaneLocality::SameLane);
+        assert_eq!(prepared_events[1].worker_id, "worker-01");
+        assert_eq!(prepared_events[1].node_id, "node-a");
+    }
