+    #[cfg(test)]
+    #[test]
+    fn test_statement_reuse_trace_distinguishes_same_lane_cross_lane_and_cross_node() {
+        let _profile_guard = StatementReuseHotPathProfileGuard::new();
+        let conn = Connection::open(":memory:").unwrap();
+        let hot_sql = "SELECT 9";
+        let hot_fingerprint = format!("{:016x}", Connection::sql_hash(hot_sql));
+
+        reset_statement_reuse_measurement(&conn);
+        {
+            let _lane = StatementReuseLaneOverrideGuard::new("worker-01", "node-a");
+            drop(conn.prepare(hot_sql).unwrap());
+            drop(conn.prepare("SELECT 10").unwrap());
+            drop(conn.prepare(hot_sql).unwrap());
+        }
+        {
+            let _lane = StatementReuseLaneOverrideGuard::new("worker-02", "node-a");
+            drop(conn.prepare("SELECT 11").unwrap());
+            drop(conn.prepare(hot_sql).unwrap());
+        }
+        {
+            let _lane = StatementReuseLaneOverrideGuard::new("worker-02", "node-b");
+            drop(conn.prepare("SELECT 12").unwrap());
+            drop(conn.prepare(hot_sql).unwrap());
+        }
+
+        let prepared_events = conn
+            .statement_reuse_trace_snapshot()
+            .into_iter()
+            .filter(|entry| {
+                entry.cache_kind == "prepared" && entry.statement_fingerprint == hot_fingerprint
+            })
+            .collect::<Vec<_>>();
+
+        assert_eq!(prepared_events.len(), 4);
+        assert_eq!(prepared_events[0].lane_locality, StatementReuseLaneLocality::FirstObservation);
+        assert_eq!(prepared_events[1].reuse_distance, Some(1));
+        assert_eq!(prepared_events[1].lane_locality, StatementReuseLaneLocality::SameLane);
+        assert_eq!(prepared_events[2].reuse_distance, Some(1));
+        assert_eq!(prepared_events[2].lane_locality, StatementReuseLaneLocality::CrossLane);
+        assert_eq!(prepared_events[2].previous_worker_id.as_deref(), Some("worker-01"));
+        assert_eq!(prepared_events[2].worker_id, "worker-02");
+        assert_eq!(prepared_events[3].reuse_distance, Some(1));
+        assert_eq!(prepared_events[3].lane_locality, StatementReuseLaneLocality::CrossNode);
+        assert_eq!(prepared_events[3].previous_node_id.as_deref(), Some("node-a"));
+        assert_eq!(prepared_events[3].node_id, "node-b");
+    }
